import { RiArrowDownSLine, RiArrowUpSLine } from 'react-icons/ri';

export function LoadMoreButton(theme: any, onClick: any, gridVisibility: boolean) {
	function handleArrowIcon() {
		return (
			<button className={`flex flex-col text-center items-center w-screen justify-center text-5xl ${theme.themeBgClassName}`} onClick={onClick}>
				{!gridVisibility ? <RiArrowDownSLine /> : <RiArrowUpSLine />}
			</button>
		);
	}

	return <>{handleArrowIcon()}</>;
}
